INSERT INTO questions (question_text, choices, correct_answer, explanation, subject, topic, difficulty, exam_type) VALUES
('What is the mean of the data set {4, 7, 8, 2, 9}?', '["6", "7", "8", "5"]', 'A', 'Mean = sum / count = (4 + 7 + 8 + 2 + 9) / 5 = 30 / 5 = 6.', 'Mathematics', 'Statistics', 'easy', 'secondary'),
('What is the median of the data set {3, 5, 7, 9, 11}?', '["7", "5", "9", "6"]', 'A', 'The median is the middle value of ordered data. Ordered: {3, 5, 7, 9, 11}. The middle (3rd) value is 7.', 'Mathematics', 'Statistics', 'easy', 'secondary'),
('What is the mode of the data set {2, 4, 4, 6, 7, 4, 9}?', '["4", "6", "2", "7"]', 'A', 'The mode is the value that appears most frequently. 4 appears three times — more than any other value.', 'Mathematics', 'Statistics', 'easy', 'secondary'),
('What is the range of the data set {15, 22, 8, 31, 14}?', '["23", "18", "31", "15"]', 'A', 'Range = maximum - minimum = 31 - 8 = 23.', 'Mathematics', 'Statistics', 'easy', 'secondary'),
('What is the probability of getting heads when flipping a fair coin?', '["1/2", "1/4", "1/3", "2/3"]', 'A', 'A fair coin has two equally likely outcomes: heads or tails. P(heads) = 1/2 = 0.5 or 50%.', 'Mathematics', 'Probability', 'easy', 'secondary'),
('What is the probability of rolling a 4 on a fair six-sided die?', '["1/6", "1/4", "1/3", "1/2"]', 'A', 'A fair die has 6 equally likely outcomes. There is only one way to roll a 4, so P(4) = 1/6.', 'Mathematics', 'Probability', 'easy', 'secondary'),
('What is the sum of all probabilities in a sample space?', '["1", "0", "0.5", "100"]', 'A', 'The sum of all probabilities in a sample space always equals 1 (or 100%). This is a fundamental axiom of probability.', 'Mathematics', 'Probability', 'easy', 'secondary'),
('What does it mean if two events are mutually exclusive?', '["They cannot occur at the same time", "They always occur together", "They are equally likely", "They are independent of each other"]', 'A', 'Mutually exclusive events cannot happen at the same time. If event A occurs, event B cannot, and vice versa.', 'Mathematics', 'Probability', 'medium', 'secondary'),
('What is the median of {2, 5, 8, 12}? (Even number of values)', '["6.5", "7", "5", "8"]', 'A', 'With an even number of values, the median is the average of the two middle values: (5 + 8) / 2 = 13 / 2 = 6.5.', 'Mathematics', 'Statistics', 'medium', 'secondary'),
('What is the probability of drawing an Ace from a standard 52-card deck?', '["1/13", "1/52", "4/13", "1/4"]', 'A', 'There are 4 Aces in a 52-card deck. P(Ace) = 4/52 = 1/13.', 'Mathematics', 'Probability', 'medium', 'secondary'),
('If the mean of five numbers is 10, what is their sum?', '["50", "10", "25", "100"]', 'A', 'Mean = sum / count. So sum = mean × count = 10 × 5 = 50.', 'Mathematics', 'Statistics', 'easy', 'secondary'),
('What is a "bar graph" used for?', '["Comparing categories using rectangular bars", "Showing change over time", "Showing parts of a whole", "Displaying the distribution of data"]', 'A', 'A bar graph (bar chart) uses rectangular bars of varying heights to compare different categories of data.', 'Mathematics', 'Statistics', 'easy', 'secondary'),
('What is the probability of rolling an even number on a fair die?', '["1/2", "1/3", "2/3", "1/6"]', 'A', 'Even numbers on a die: {2, 4, 6} — three outcomes out of six. P(even) = 3/6 = 1/2.', 'Mathematics', 'Probability', 'easy', 'secondary'),
('What is the term for a graph that shows the distribution of data along a number line?', '["Histogram", "Line graph", "Pie chart", "Scatter plot"]', 'A', 'A histogram displays the frequency distribution of continuous data using adjacent bars, with data grouped into intervals (bins).', 'Mathematics', 'Statistics', 'medium', 'secondary'),
('What is the probability that two independent events A and B both occur?', '["P(A) × P(B)", "P(A) + P(B)", "P(A) - P(B)", "P(A) / P(B)"]', 'A', 'For independent events, the probability that both occur is the product of their individual probabilities: P(A and B) = P(A) × P(B).', 'Mathematics', 'Probability', 'medium', 'secondary'),
('What is the mean of {10, 20, 30, 40, 50}?', '["30", "25", "35", "40"]', 'A', 'Mean = (10 + 20 + 30 + 40 + 50) / 5 = 150 / 5 = 30.', 'Mathematics', 'Statistics', 'easy', 'secondary'),
('What is standard deviation a measure of?', '["How spread out the data values are from the mean", "The middle value in a data set", "The most frequent value", "The difference between highest and lowest values"]', 'A', 'Standard deviation measures the average distance (spread) of each data point from the mean. A higher SD means more spread out data.', 'Mathematics', 'Statistics', 'medium', 'secondary'),
('Two fair coins are flipped. What is the probability of getting two heads?', '["1/4", "1/2", "1/3", "3/4"]', 'A', 'P(HH) = P(H) × P(H) = 1/2 × 1/2 = 1/4. (Independent events: multiply probabilities.)', 'Mathematics', 'Probability', 'medium', 'secondary'),
('What type of graph shows how parts make up a whole?', '["Pie chart", "Bar graph", "Line graph", "Histogram"]', 'A', 'A pie chart (circle graph) shows the relative proportions of parts to a whole, with each "slice" representing a category.', 'Mathematics', 'Statistics', 'easy', 'secondary'),
('In a class of 30 students, 12 are boys. What is the probability of randomly selecting a girl?', '["3/5", "2/5", "1/2", "1/3"]', 'A', 'Number of girls = 30 - 12 = 18. P(girl) = 18/30 = 3/5.', 'Mathematics', 'Probability', 'medium', 'secondary'),
('What is the mode of a data set with no repeated values?', '["There is no mode", "The mean is the mode", "The median is the mode", "Zero is the mode"]', 'A', 'If no value appears more than once, the data set has no mode. Mode only exists when at least one value repeats.', 'Mathematics', 'Statistics', 'easy', 'secondary'),
('What is the probability that when rolling two dice, the sum equals 7?', '["1/6", "1/12", "7/36", "6/36"]', 'A', 'Pairs summing to 7: (1,6), (2,5), (3,4), (4,3), (5,2), (6,1) = 6 pairs. Total outcomes = 36. P(sum=7) = 6/36 = 1/6.', 'Mathematics', 'Probability', 'hard', 'secondary'),
('What is a "line graph" best used for?', '["Showing trends or changes over time", "Comparing categories", "Showing parts of a whole", "Displaying frequency distributions"]', 'A', 'A line graph uses points connected by lines to show how data changes over time or across ordered categories.', 'Mathematics', 'Statistics', 'easy', 'secondary'),
('What is a "complementary event"?', '["The probability that an event does NOT occur (1 - P(A))", "Two events that occur at the same time", "Events that are equally likely", "Events that depend on each other"]', 'A', 'The complement of event A is the event that A does NOT occur. P(A complement) = 1 - P(A).', 'Mathematics', 'Probability', 'medium', 'secondary'),
('The mean of a data set is 15 and there are 8 values. One value is 20. What is the mean of the remaining 7 values?', '["110/7 ≈ 14.3", "15", "13", "12"]', 'A', 'Total sum = 15 × 8 = 120. Remaining sum = 120 - 20 = 100. Wait: 100/7 ≈ 14.3. Actually mean of remaining 7 = (120-20)/7 = 100/7 ≈ 14.3.', 'Mathematics', 'Statistics', 'hard', 'secondary'),
('What does a "scatter plot" show?', '["The relationship between two variables", "The frequency of one variable", "Parts of a whole", "Change over time"]', 'A', 'A scatter plot displays data points for two variables on a coordinate plane to show the relationship (correlation) between them.', 'Mathematics', 'Statistics', 'medium', 'secondary'),
('A bag contains 3 red, 4 blue, and 5 green balls. What is the probability of picking a blue ball?', '["1/3", "1/4", "4/12", "5/12"]', 'A', 'Total balls = 3 + 4 + 5 = 12. P(blue) = 4/12 = 1/3.', 'Mathematics', 'Probability', 'medium', 'secondary'),
('What is the term for the middle 50% of data in a box plot?', '["Interquartile range (IQR)", "Range", "Standard deviation", "Variance"]', 'A', 'The interquartile range (IQR) = Q3 - Q1, representing the middle 50% of data and measuring spread without being affected by outliers.', 'Mathematics', 'Statistics', 'hard', 'secondary'),
('What is the probability of rolling a number less than 3 on a fair die?', '["1/3", "1/2", "2/3", "1/6"]', 'A', 'Numbers less than 3 on a die: {1, 2} — two outcomes out of six. P = 2/6 = 1/3.', 'Mathematics', 'Probability', 'easy', 'secondary'),
('What is the mean absolute deviation (MAD) a measure of?', '["The average distance of each data point from the mean", "The most common value in the data", "The difference between maximum and minimum values", "The sum of all values divided by count"]', 'A', 'Mean absolute deviation (MAD) measures the average of the absolute differences between each data point and the mean, indicating typical spread.', 'Mathematics', 'Statistics', 'hard', 'secondary'),
('What is the probability of drawing a heart or a diamond from a standard 52-card deck?', '["1/2", "1/4", "1/13", "2/13"]', 'A', 'Hearts: 13 cards. Diamonds: 13 cards. Total = 26. P = 26/52 = 1/2.', 'Mathematics', 'Probability', 'medium', 'secondary'),
('Which measure of central tendency is most affected by extreme values (outliers)?', '["Mean", "Median", "Mode", "Range"]', 'A', 'The mean is most sensitive to outliers because it uses all values in the calculation. The median and mode are more resistant to extreme values.', 'Mathematics', 'Statistics', 'medium', 'secondary'),
('A spinner has 5 equal sections numbered 1-5. What is the probability of landing on an odd number?', '["3/5", "2/5", "1/5", "4/5"]', 'A', 'Odd numbers {1, 3, 5} = 3 sections out of 5. P(odd) = 3/5.', 'Mathematics', 'Probability', 'easy', 'secondary'),
('What is the formula for P(A or B) when A and B are mutually exclusive?', '["P(A) + P(B)", "P(A) × P(B)", "P(A) - P(B)", "P(A) + P(B) - P(A and B)"]', 'A', 'For mutually exclusive events, P(A or B) = P(A) + P(B) because they cannot overlap (P(A and B) = 0).', 'Mathematics', 'Probability', 'medium', 'secondary'),
('A survey of 50 students found 20 like Math and 15 like Science. 8 like both. How many like either Math or Science?', '["27", "35", "43", "28"]', 'A', 'P(Math or Science) = P(Math) + P(Science) - P(Both) = 20 + 15 - 8 = 27.', 'Mathematics', 'Probability', 'hard', 'secondary'),
('What is a "frequency table"?', '["A table showing how often each value occurs in a data set", "A table of mathematical formulas", "A table comparing two data sets", "A table sorted by time"]', 'A', 'A frequency table organizes data by showing how many times (frequency) each value or group of values occurs.', 'Mathematics', 'Statistics', 'easy', 'secondary'),
('What is the probability of getting at least one head when flipping two coins?', '["3/4", "1/2", "1/4", "1"]', 'A', 'P(at least one head) = 1 - P(no heads) = 1 - P(TT) = 1 - 1/4 = 3/4.', 'Mathematics', 'Probability', 'medium', 'secondary'),
('Which measure of spread is calculated as Q3 minus Q1?', '["Interquartile range", "Range", "Standard deviation", "Variance"]', 'A', 'The interquartile range (IQR) = Q3 - Q1. It represents the spread of the middle 50% of data.', 'Mathematics', 'Statistics', 'medium', 'secondary'),
('What type of correlation is shown when high values of X correspond to high values of Y?', '["Positive correlation", "Negative correlation", "No correlation", "Perfect correlation"]', 'A', 'Positive correlation means as one variable increases, the other tends to increase as well. Shown as an upward trend in a scatter plot.', 'Mathematics', 'Statistics', 'medium', 'secondary'),
('What is the expected value when rolling a single fair die?', '["3.5", "3", "4", "2.5"]', 'A', 'Expected value = (1 + 2 + 3 + 4 + 5 + 6) / 6 = 21 / 6 = 3.5.', 'Mathematics', 'Probability', 'medium', 'secondary'),
('What is the mode of the data set {5, 5, 5, 8, 8, 9}?', '["5", "8", "6.7", "5 and 8"]', 'A', 'The mode is the most frequently occurring value. 5 appears three times (most frequent), so the mode is 5.', 'Mathematics', 'Statistics', 'easy', 'secondary'),
('What does "independent events" mean in probability?', '["The outcome of one event does not affect the other", "The events always occur together", "The events cannot occur together", "Both events have equal probability"]', 'A', 'Independent events are those where the outcome of one event does not affect the probability of the other event occurring.', 'Mathematics', 'Probability', 'medium', 'secondary'),
('What is the median of {1, 3, 5, 7, 9, 11}?', '["6", "5", "7", "5.5"]', 'A', 'With 6 values, median = average of 3rd and 4th values = (5 + 7) / 2 = 12 / 2 = 6.', 'Mathematics', 'Statistics', 'medium', 'secondary'),
('A card is drawn from a deck. What is the probability that it is a face card (Jack, Queen, King)?', '["3/13", "1/13", "1/4", "3/52"]', 'A', 'Face cards: 3 per suit × 4 suits = 12 face cards out of 52. P = 12/52 = 3/13.', 'Mathematics', 'Probability', 'medium', 'secondary'),
('What is the variance related to?', '["The square of the standard deviation", "The range of the data", "The average of the data", "The mode of the data"]', 'A', 'Variance is the square of the standard deviation (σ²). It measures the spread of data by averaging the squared deviations from the mean.', 'Mathematics', 'Statistics', 'hard', 'secondary'),
('What is a "bimodal" data set?', '["A data set with two modes", "A data set with no mode", "A data set with very large values", "A data set in two columns"]', 'A', 'A bimodal data set has exactly two modes — two values that both appear with the same highest frequency.', 'Mathematics', 'Statistics', 'medium', 'secondary'),
('What is P(rolling a 7) on a standard six-sided die?', '["0 (impossible)", "1/7", "1/6", "7/36"]', 'A', 'A standard die has faces 1-6. Rolling a 7 is impossible, so P(7) = 0.', 'Mathematics', 'Probability', 'easy', 'secondary'),
('In a data set, what does an outlier affect most significantly?', '["The mean", "The median", "The mode", "The range only"]', 'A', 'An outlier (extreme value) significantly affects the mean because the mean uses all values. The median is more robust to outliers.', 'Mathematics', 'Statistics', 'medium', 'secondary'),
('What is the probability of drawing a red card from a standard deck?', '["1/2", "1/4", "1/13", "1/26"]', 'A', 'Red cards: hearts (13) + diamonds (13) = 26 out of 52. P(red) = 26/52 = 1/2.', 'Mathematics', 'Probability', 'easy', 'secondary'),
('What is a "sample" in statistics?', '["A subset of a population used to represent the whole", "The entire group being studied", "A single data point", "A type of graph"]', 'A', 'A sample is a subset selected from the population to represent it. Studying a sample is more practical than studying an entire population.', 'Mathematics', 'Statistics', 'easy', 'secondary');
